from collections import deque
n,m=map(int,input().split())
g=[[] for _ in range(n)]
for _ in range(m):
    u,v=map(int,input().split())
    g[u].append(v);g[v].append(u)
col=[-1]*n
def bfs(s):
    col[s]=0;q=deque([s])
    while q:
        u=q.popleft()
        for v in g[u]:
            if col[v]==-1:col[v]=1-col[u];q.append(v)
            elif col[v]==col[u]:return False
    return True
print('YES' if all(col[i]!=-1 or bfs(i) for i in range(n)) else 'NO')

